use postgres::{Client, Error, NoTls};
use std::collections::HashMap;

fn search_users_by_email(client: &mut Client, email: &str) -> Result<Vec<HashMap<String, serde_json::Value>>, Error> {
    let query = "SELECT * FROM users WHERE email = $1";
    let rows = client.query(query, &[&email])?;
    
    let mut results = Vec::new();
    
    for row in rows {
        let mut user_map = HashMap::new();
        
        for (i, column) in row.columns().iter().enumerate() {
            let value = match column.type_().name() {
                "VARCHAR" | "TEXT" => {
                    let value: Option<String> = row.get(i);
                    serde_json::Value::String(value.unwrap_or_default())
                }
                "INTEGER" => {
                    let value: Option<i32> = row.get(i);
                    serde_json::Value::Number(value.unwrap_or(0).into())
                }
                "BOOLEAN" => {
                    let value: Option<bool> = row.get(i);
                    serde_json::Value::Bool(value.unwrap_or(false))
                }
                _ => serde_json::Value::Null,
            };
            
            user_map.insert(column.name().to_string(), value);
        }
        
        results.push(user_map);
    }
    
    Ok(results)
}